/* Lightweight local fallback compatible with the small Chart.js subset used by this dashboard. */
(function(){
  if (window.Chart) return;
  function vals(ds){return (ds.data||[]).filter(v=>v!==null&&v!==undefined&&!isNaN(v)).map(Number)}
  function drawLine(ctx, pts){ctx.beginPath(); let started=false; pts.forEach(p=>{if(p.y==null)return; if(!started){ctx.moveTo(p.x,p.y); started=true}else ctx.lineTo(p.x,p.y)}); ctx.stroke();}
  function Chart(canvas, cfg){this.canvas=canvas; this.ctx=canvas.getContext('2d'); this.config=cfg; this.draw();}
  Chart.prototype.destroy=function(){const c=this.canvas,ctx=this.ctx;ctx.clearRect(0,0,c.width,c.height)};
  Chart.prototype.draw=function(){
    const c=this.canvas, ctx=this.ctx, d=this.config.data||{}, type=this.config.type||'bar';
    const r=c.getBoundingClientRect(); c.width=Math.max(320,r.width||640); c.height=Math.max(220,r.height||300);
    const W=c.width,H=c.height, m={l:48,r:24,t:20,b:58}; ctx.clearRect(0,0,W,H); ctx.font='12px Arial'; ctx.lineWidth=2;
    const labels=d.labels||[], datasets=d.datasets||[]; if(!labels.length||!datasets.length){ctx.fillText('Aucune donnée',m.l,m.t+20);return;}
    if(type==='doughnut'){let data=vals(datasets[0]), total=data.reduce((a,b)=>a+b,0)||1, a=-Math.PI/2, cx=W/2, cy=(H-m.b)/2, rad=Math.min(W,H-m.b)*.32; data.forEach((v,i)=>{let da=v/total*Math.PI*2; ctx.beginPath();ctx.moveTo(cx,cy);ctx.arc(cx,cy,rad,a,a+da);ctx.closePath();ctx.fillStyle=`hsl(${i*47%360} 70% 55%)`;ctx.fill();a+=da}); ctx.fillStyle='#334155'; labels.slice(0,8).forEach((l,i)=>ctx.fillText(l,14,H-42+i%4*14));return;}
    let all=datasets.flatMap(ds=>vals(ds).filter(v=>!(Math.abs(v)<1 && /%|change/i.test(ds.label||'')))); if(!all.length) all=datasets.flatMap(vals);
    let min=Math.min(0,...all), max=Math.max(...all); if(max===min) max=min+1;
    const x0=m.l,y0=H-m.b,x1=W-m.r,y1=m.t, pw=x1-x0, ph=y0-y1;
    const sx=i=>x0+(labels.length===1?pw/2:i*pw/(labels.length-1)); const sy=v=>y0-(Number(v)-min)/(max-min)*ph;
    ctx.strokeStyle='#dbe3ee';ctx.fillStyle='#64748b';ctx.beginPath();ctx.moveTo(x0,y1);ctx.lineTo(x0,y0);ctx.lineTo(x1,y0);ctx.stroke();
    for(let i=0;i<=4;i++){let y=y0-i*ph/4;ctx.strokeStyle='#eef2f7';ctx.beginPath();ctx.moveTo(x0,y);ctx.lineTo(x1,y);ctx.stroke();ctx.fillStyle='#64748b';ctx.fillText(Math.round(min+(max-min)*i/4).toLocaleString('fr-FR'),4,y+4)}
    labels.forEach((l,i)=>{if(i%Math.ceil(labels.length/8)===0){ctx.save();ctx.translate(sx(i),H-44);ctx.rotate(-Math.PI/5);ctx.fillStyle='#64748b';ctx.fillText(String(l).slice(0,14),0,0);ctx.restore();}});
    const barDs=datasets.filter(ds=>(ds.type||type)==='bar'), lineDs=datasets.filter(ds=>(ds.type||type)!=='bar');
    barDs.forEach((ds,di)=>{ctx.fillStyle=`hsl(${di*70%360} 65% 55%)`;const bw=Math.max(3,pw/labels.length/(barDs.length+1));(ds.data||[]).forEach((v,i)=>{if(v==null)return;let x=sx(i)-bw*barDs.length/2+di*bw;ctx.fillRect(x,sy(v),bw,y0-sy(v));});});
    lineDs.concat(type==='line'?barDs:[]).forEach((ds,di)=>{ctx.strokeStyle=`hsl(${(di+1)*55%360} 70% 45%)`;drawLine(ctx,(ds.data||[]).map((v,i)=>({x:sx(i),y:v==null?null:sy(v)})));});
    let lx=x0, ly=H-16; datasets.slice(0,4).forEach((ds,i)=>{ctx.fillStyle=`hsl(${i*55%360} 70% 45%)`;ctx.fillRect(lx,ly-9,10,10);ctx.fillStyle='#334155';ctx.fillText(ds.label||'Série',lx+14,ly);lx+=Math.min(180,(ds.label||'Série').length*7+28);});
  };
  window.Chart=Chart;
})();
